args.sparql:
SELECT ?location WHERE {
  ?season wdt:P155 wd:Q2308652;
         wdt:P154 ?seasonNumber.
  ?season wdt:P495 ?location.
}
ORDER BY DESC(?seasonNumber)
LIMIT 1

SELECT ?locationLabel WHERE {
  ?season wdt:P155 wd:Q1247321 ;
         wdt:P154 ?seasonNumber .
  ?season wdt:P276 ?location .
  ?location rdfs:label ?locationLabel .
  FILTER (LANG(?locationLabel) = 'en')
}
ORDER BY DESC(?seasonNumber)
LIMIT 1

SELECT ?locationLabel WHERE {
  ?season wdt:P155 wd:Q1247321;
          wdt:P154 ?seasonNumber.
  ?season wdt:P495 ?location.
  ?location rdfs:label ?locationLabel.
  FILTER (LANG(?locationLabel) = 'en')
}
ORDER BY DESC(?seasonNumber)
LIMIT 1
